"use client";

import AboutSection from "@/components/about-page/AboutSection";
import ExperienceTimeline from "@/components/about-page/ExperienceTimeline";
import CurrentlyReadingCard from "@/components/about-page/ui/CurrentlyReadingCard";
import RecentFavoriteCard from "@/components/about-page/ui/RecentFavoriteCard";
import ScrapBookCard from "@/components/about-page/ui/ScrapBookCard";
import StatsCard from "@/components/about-page/ui/StatsCard";
import ConnectionsCard from "@/components/ui/ConnectionsCard";
import ThreeDragImages from "@/components/ui/ThreeDragImages";
import { useEffect, useRef, useState } from "react";

function Page() {
  const [scrollProgress, setScrollProgress] = useState(0);
  const [greeting, setGreeting] = useState("Good evening");
  const timelineRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    // Function to get greeting based on current time
    const getGreeting = () => {
      const hour = new Date().getHours();

      if (hour >= 5 && hour < 12) {
        return "Good morning";
      } else if (hour >= 12 && hour < 17) {
        return "Good afternoon";
      } else {
        return "Good evening";
      }
    };

    // Set initial greeting
    setGreeting(getGreeting());

    // Update greeting every minute
    const greetingInterval = setInterval(() => {
      setGreeting(getGreeting());
    }, 60000);

    return () => clearInterval(greetingInterval);
  }, []);

  useEffect(() => {
    const handleScroll = () => {
      // Story timeline scroll progress
      if (timelineRef.current) {
        const rect = timelineRef.current.getBoundingClientRect();
        const windowHeight = window.innerHeight;

        // Calculate progress based on element position
        const elementTop = rect.top;
        const elementHeight = rect.height;

        // Start tracking when element enters viewport, end when it leaves
        const start = windowHeight;
        const end = -elementHeight;
        const progress = 1 - (elementTop - end) / (start - end);

        const clampedProgress = Math.max(0, Math.min(1, progress));
        setScrollProgress(clampedProgress);
        console.log(scrollProgress);
      }
    };

    window.addEventListener("scroll", handleScroll, { passive: true });
    handleScroll(); // Initial calculation

    return () => window.removeEventListener("scroll", handleScroll);
  }, []);

  return (
    <div className="overflow-x-hidden overflow-y-hidden">
      {/* Hero Section */}
      <main
        className="space-y-12 relative w-full before:absolute before:top-0
       before:h-px before:bg-border-primary/50 before:-left-4 before:right-4
        md:before:-left-8 md:before:right-8 lg:before:inset-x-0 after:-left-4
         after:right-4 md:after:-left-8 md:after:right-8 lg:after:inset-x-0 
         after:absolute after:bottom-0 after:h-px after:bg-border-primary/50"
      >
        <div className="flex flex-col lg:flex-row-reverse lg:items-center lg:justify-around lg:px-24">
          <div className="order-2 mx-auto max-w-lg lg:order-1 lg:m-0 lg:max-w-3xl lg:pr-12">
            <div
              className="text-center text-sm font-medium text-indigo-600 lg:text-left"
              data-aos="zoom-in"
            >
              <span>{greeting}!</span>
            </div>
            <h1
              className="mx-auto max-w-2xl text-balance text-center
             text-4xl font-medium leading-tight tracking-tighter text-text-primary 
             md:text-5xl lg:text-left lg:text-6xl lg:leading-16"
              data-aos="fade-right"
            >
              I&apos;m Kelvin, a creative frontend engineer.
            </h1>
          </div>

          {/* Draggable cards */}
          <ThreeDragImages />
        </div>
      </main>

      <span className="absolute left-1/2 top-40 -translate-y-1/2 translate-x-1/2">
        <span className="absolute left-1/2 h-px w-full -translate-x-1/2 transform bg-border-primary/50"></span>
      </span>

      {/* About Section */}
      <AboutSection />

      {/* xperience */}
      <ExperienceTimeline />

      {/* scrap book side */}
      <section className="relative space-y-16 mt-[100px] mb-[50px]">
        {/* Header */}
        <div className="space-y-4">
          <div
            className="relative w-full before:absolute before:top-0 before:h-px
           before:bg-border-primary/50 before:-left-4 before:-right-4 md:before:-left-8
            md:before:-right-8 lg:before:inset-x-0 after:-left-4 after:-right-4
             md:after:-left-8 md:after:-right-8 lg:after:inset-x-0 after:absolute after:bottom-0
              after:h-px after:bg-border-primary/50"
          >
            <div className="text-center text-sm font-medium text-indigo-600">
              <span>More</span>
            </div>
          </div>
          <div
            className="relative w-full before:absolute before:top-0
           before:h-px before:bg-border-primary/50 before:-left-4 before:-right-4
            md:before:-left-8 md:before:-right-8 lg:before:inset-x-0 after:-left-4 
            after:-right-4 md:after:-left-8 md:after:-right-8 lg:after:inset-x-0
             after:absolute after:bottom-0 after:h-px after:bg-border-primary/50"
          >
            <h2 className="mx-auto max-w-lg text-balance text-center text-3xl font-medium leading-10 tracking-tight text-text-primary">
              A sneak Peak Into My random board, main version coming soon
            </h2>
          </div>
        </div>

        {/* Grid Layout */}
        <div
          className="relative w-full px-3 md:px-[30px] before:absolute before:top-0 
        before:h-px before:bg-border-primary/50 before:-left-4 before:-right-4 
        md:before:-left-8 md:before:-right-8 lg:before:inset-x-0 after:-left-4 after:-right-4 
        md:after:-left-8 md:after:-right-8 lg:after:inset-x-0 after:absolute after:bottom-0 after:h-px 
        after:bg-border-primary/50"
        >
          <div className="grid grid-cols-1 gap-2 lg:grid-cols-12">
            {/* Recent Favorite - Music */}
            <RecentFavoriteCard />

            {/* Scrapbook */}
            <ScrapBookCard />

            {/* Currently Reading */}
            <CurrentlyReadingCard />

            {/* Connections */}
            <ConnectionsCard />

            {/* Stats */}
            <StatsCard />
          </div>
        </div>
      </section>
    </div>
  );
}

export default Page;

